import PostCard from "../components/PostCard";

export default function Home() {
    const dummyPosts = [
        {
            title: "Nueva sede de rehabilitación inaugurada",
            excerpt: "<p>Con gran alegría anunciamos la apertura de nuestro nuevo centro especializado para la atención integral de niños...</p>",
            slug: "nueva-sede-inaugurada",
            date: "2025-04-15T12:00:00Z",
            // Placeholder image or real image from the JSON later
        },
        {
            title: "Campaña de apadrinamiento 2025",
            excerpt: "<p>Súmate a nuestra causa y ayuda a cambiar la vida de más de 100 familias a través de nuestro programa integral de apoyo...</p>",
            slug: "campana-apadrinamiento-2025",
            date: "2025-03-20T09:30:00Z",
        },
        {
            title: "Resultados del Congreso Internacional NDT/Bobath",
            excerpt: "<p>Expertos de todo el mundo se reunieron para debatir los avances más recientes en la neuro-rehabilitación pediátrica...</p>",
            slug: "resultados-congreso-internacional",
            date: "2025-02-10T14:15:00Z",
        }
    ];

    return (
        <div className="max-w-7xl mx-auto py-12 px-4 sm:px-6 lg:px-8">
            <section className="text-center mb-16">
                <h2 className="text-4xl md:text-5xl font-bold mb-6 text-gray-900 dark:text-white">
                    Transformando Vidas <br />
                    <span className="text-primary">Paso a Paso</span>
                </h2>
                <p className="text-xl text-gray-600 dark:text-gray-300 max-w-3xl mx-auto">
                    Somos una organización dedicada a la rehabilitación neuro-lógica integral, apoyando a niños y familias desde hace 30 años.
                </p>
            </section>

            <section>
                <div className="flex items-center justify-between mb-8">
                    <h3 className="text-3xl font-bold text-gray-900 dark:text-white border-b-4 border-primary pb-2 inline-block">Últimas Noticias</h3>
                    <a href="/noticias" className="hidden sm:block text-primary hover:text-primary-dark font-medium transition-colors">
                        Ver todas →
                    </a>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {dummyPosts.map((post, index) => (
                        <PostCard
                            key={index}
                            title={post.title}
                            excerpt={post.excerpt}
                            slug={post.slug}
                            date={post.date}
                        />
                    ))}
                </div>
            </section>
        </div>
    );
}
